// ═══════════════════════════════════════════════════════════════════════
// SALVAGEPUNK SALON - Generative baroque portrait frame with decay
// Synthograsizer Workflow Template
// ═══════════════════════════════════════════════════════════════════════

const CW = 768;

let figurePoints = [];
let ambientParticles = [];
let glitchBlocks = [];
let glitchTimer = 60;
let _prevFrameHue = -1;
let _prevBgStyle = '';

p.setup = function() {
  p.createCanvas(CW, CW);
  p.colorMode(p.HSB, 360, 100, 100, 100);

  // Radial blob points for the generative figure silhouette
  let nPts = 22;
  for (let i = 0; i < nPts; i++) {
    figurePoints.push({
      angle: (i / nPts) * p.TWO_PI,
      baseR: p.random(0.72, 1.0),
      noiseOff: p.random(10000)
    });
  }

  // Ambient dust floating inside portrait area
  for (let i = 0; i < 50; i++) {
    ambientParticles.push(newDustParticle());
  }
};

function newDustParticle() {
  return {
    x: p.random(CW * 0.18, CW * 0.82),
    y: p.random(CW * 0.2, CW * 0.88),
    vx: p.random(-0.22, 0.22),
    vy: p.random(-0.55, -0.08),
    size: p.random(1.5, 7),
    alpha: p.random(8, 44),
    hueOff: p.random(-40, 40),
    noiseOff: p.random(1000)
  };
}

p.draw = function() {
  let frameHue    = parseFloat(p.getSynthVar('frame_hue'))   || 45;
  let subjectHue  = parseFloat(p.getSynthVar('subject_hue')) || 210;
  let decay       = parseFloat(p.getSynthVar('decay'))       || 30;
  let glowDensity = parseInt(p.getSynthVar('glow_density'))  || 2500;
  let bgStyle     = p.getSynthVar('bg_style')                || 'velvet';
  let t = p.frameCount;

  let hueChanged = (frameHue !== _prevFrameHue || bgStyle !== _prevBgStyle);
  _prevFrameHue = frameHue;
  _prevBgStyle = bgStyle;

  if (hueChanged) { p.background(frameHue, 18, 7); }

  // Semi-transparent overlay for motion trails
  p.noStroke();
  p.fill(frameHue, 18, 7, 18);
  p.rect(0, 0, CW, CW);

  // Periodic full clear to prevent muddiness
  if (t % 100 === 1) { p.background(frameHue, 18, 7); }

  // ─── Background texture ───────────────────────────────────────────────
  if (bgStyle === 'velvet') {
    for (let i = 0; i < 40; i++) {
      let x = p.random(CW), y = p.random(CW);
      p.stroke(frameHue, p.random(20, 55), p.random(10, 32), p.random(4, 18));
      p.strokeWeight(1);
      p.point(x, y);
    }
  } else if (bgStyle === 'mottled') {
    p.noStroke();
    for (let i = 0; i < 18; i++) {
      let x = p.random(CW), y = p.random(CW);
      let sz = p.random(8, 55);
      p.fill(frameHue, p.random(10, 45), p.random(5, 26), p.random(3, 14));
      p.ellipse(x, y, sz, sz * p.random(0.4, 1.8));
    }
  }

  // ─── Chiaroscuro portrait glow ────────────────────────────────────────
  let breathe = 1 + Math.sin(t * 0.022) * 0.018;
  let cx = CW / 2;
  let cy = CW * 0.485;
  p.noStroke();
  for (let r = 270; r > 55; r -= 18) {
    let alpha = p.map(r, 55, 270, 20, 1) * breathe;
    p.fill(subjectHue, 28, 38, alpha);
    p.ellipse(cx, cy, r * 2.1, r * 2.45);
  }

  // ─── Generative figure silhouette ─────────────────────────────────────
  p.push();
  p.translate(cx, cy + CW * 0.05);
  let figW = CW * 0.19 * breathe;
  let figH = CW * 0.26 * breathe;

  // Drop shadow
  p.noStroke();
  p.fill(subjectHue, 65, 7, 32);
  p.ellipse(10, 18, figW * 1.95, figH * 1.5);

  // Body blob — noise-driven radial shape
  p.beginShape();
  for (let i = 0; i <= figurePoints.length + 2; i++) {
    let fp = figurePoints[i % figurePoints.length];
    let nv = p.noise(fp.noiseOff + t * 0.007) * 0.30 + 0.78;
    let r = fp.baseR * nv;
    p.curveVertex(Math.cos(fp.angle) * figW * r, Math.sin(fp.angle) * figH * r);
  }
  p.fill(subjectHue, 38, 21, 93);
  p.endShape(p.CLOSE);

  // Head
  let headY = -figH * 0.88;
  let headR = figW * 0.53;
  p.fill(subjectHue, 32, 28, 93);
  p.ellipse(0, headY, headR * 2, headR * 2.18);

  // Beady eyes
  let eyeSep = headR * 0.3;
  p.fill(0, 0, 4, 98);
  p.ellipse(-eyeSep, headY + headR * 0.04, headR * 0.18, headR * 0.28);
  p.ellipse( eyeSep, headY + headR * 0.04, headR * 0.18, headR * 0.28);
  // Eye glints
  p.fill(0, 0, 100, 52);
  p.ellipse(-eyeSep + 1.5, headY - headR * 0.04, headR * 0.055, headR * 0.055);
  p.ellipse( eyeSep + 1.5, headY - headR * 0.04, headR * 0.055, headR * 0.055);

  p.pop();

  // ─── Ambient dust particles ───────────────────────────────────────────
  let glowTarget = Math.max(20, Math.floor(glowDensity / 80));
  while (ambientParticles.length < glowTarget) ambientParticles.push(newDustParticle());
  while (ambientParticles.length > glowTarget) ambientParticles.pop();

  p.noStroke();
  for (let ap of ambientParticles) {
    ap.x += ap.vx + Math.sin(t * 0.018 + ap.noiseOff) * 0.26;
    ap.y += ap.vy;
    let hue = ((subjectHue + ap.hueOff) % 360 + 360) % 360;
    let flicker = 0.62 + Math.sin(t * 0.09 + ap.noiseOff) * 0.38;
    p.fill(hue, 35, 92, ap.alpha * flicker);
    p.ellipse(ap.x, ap.y, ap.size);
    if (ap.y < CW * 0.08 || ap.x < CW * 0.09 || ap.x > CW * 0.91) {
      Object.assign(ap, newDustParticle());
    }
  }

  // ─── Ornate baroque frame (drawn on top) ──────────────────────────────
  drawSalonFrame(frameHue, decay, t);

  // ─── Glitch artifacts ─────────────────────────────────────────────────
  if (decay > 8) {
    glitchTimer--;
    if (glitchTimer <= 0) {
      glitchTimer = Math.max(8, Math.floor(p.random(40, 130) - decay * 0.75));
      let nNew = Math.floor(decay / 28) + 1;
      for (let k = 0; k < nNew; k++) {
        glitchBlocks.push({
          x: p.random(CW * 0.05, CW * 0.87),
          y: p.random(CW * 0.05, CW * 0.87),
          w: p.random(14, 135),
          h: p.random(1.5, 9),
          life: p.random(2, 10),
          hue: p.random(360)
        });
      }
    }
    p.noStroke();
    for (let i = glitchBlocks.length - 1; i >= 0; i--) {
      let gb = glitchBlocks[i];
      p.fill(gb.hue, 78, 98, p.map(gb.life, 0, 10, 0, 52));
      p.rect(gb.x, gb.y, gb.w, gb.h);
      gb.x += p.random(-2, 2);
      gb.life--;
      if (gb.life <= 0) glitchBlocks.splice(i, 1);
    }
  }
};

function drawSalonFrame(frameHue, decay, t) {
  let m = 16;
  let W = CW - m * 2;
  let H = CW - m * 2;
  p.noFill();

  // Stacked moulding layers simulating carved gilt wood
  let mouldings = [
    { inset: 0,  sw: 30, sBri: 72, sAlpha: 90 },
    { inset: 15, sw: 5,  sBri: 98, sAlpha: 85 },
    { inset: 20, sw: 18, sBri: 56, sAlpha: 88 },
    { inset: 34, sw: 4,  sBri: 96, sAlpha: 82 },
    { inset: 38, sw: 12, sBri: 44, sAlpha: 85 },
    { inset: 47, sw: 3,  sBri: 90, sAlpha: 80 },
    { inset: 51, sw: 7,  sBri: 64, sAlpha: 74 }
  ];

  for (let ml of mouldings) {
    let shimmer = Math.sin(t * 0.012 + ml.inset * 0.09) * 7;
    p.stroke(frameHue + shimmer, 58, ml.sBri, ml.sAlpha);
    p.strokeWeight(ml.sw);
    p.rect(m + ml.inset, m + ml.inset, W - ml.inset * 2, H - ml.inset * 2, 6);
  }

  // Inner portrait mat line
  p.stroke(0, 0, 6, 92);
  p.strokeWeight(2);
  p.rect(m + 60, m + 60, W - 120, H - 120, 3);

  // Verdigris / rust decay patches along frame edges
  if (decay > 4) {
    let nSpots = Math.ceil(decay / 6);
    p.noStroke();
    for (let i = 0; i < nSpots; i++) {
      let posAlong = p.noise(i * 4.17 + 99);
      let side = i % 4;
      let jitter = p.noise(i * 2.3, t * 0.003) * 24 - 12;
      let x, y;
      if      (side === 0) { x = m + posAlong * W; y = m + jitter; }
      else if (side === 1) { x = m + posAlong * W; y = m + H + jitter; }
      else if (side === 2) { x = m + jitter;       y = m + posAlong * H; }
      else                 { x = m + W + jitter;   y = m + posAlong * H; }
      let vhue   = (frameHue + 155 + p.random(-25, 25)) % 360;
      let valpha = p.map(decay, 4, 100, 18, 72) * (0.65 + p.noise(i * 1.7, t * 0.004) * 0.65);
      p.fill(vhue, 50, 46, valpha);
      p.ellipse(x, y, p.random(4, 20), p.random(3, 15));
    }
  }

  // Corner rosettes
  let corners = [
    [m + 57, m + 57],
    [CW - m - 57, m + 57],
    [m + 57, CW - m - 57],
    [CW - m - 57, CW - m - 57]
  ];
  let pulse = 1 + Math.sin(t * 0.025) * 0.045;
  for (let [ox, oy] of corners) {
    // Outer petals
    for (let petal = 0; petal < 8; petal++) {
      let ang = (petal / 8) * p.TWO_PI + t * 0.003;
      let px = ox + Math.cos(ang) * 18 * pulse;
      let py = oy + Math.sin(ang) * 18 * pulse;
      p.noStroke();
      p.fill(frameHue, 65, 80, 68);
      p.ellipse(px, py, 9 * pulse, 9 * pulse);
    }
    // Concentric rings
    for (let r = 24; r >= 5; r -= 6) {
      p.stroke(frameHue, 68, p.map(r, 5, 24, 100, 60), p.map(r, 5, 24, 95, 42));
      p.strokeWeight(2);
      p.noFill();
      p.ellipse(ox, oy, r * 2 * pulse, r * 2 * pulse);
    }
    // Center jewel
    p.noStroke();
    p.fill(frameHue + 25, 85, 100, 92);
    p.ellipse(ox, oy, 11 * pulse, 11 * pulse);
    p.fill(0, 0, 100, 56);
    p.ellipse(ox - 2.5, oy - 2.5, 3.5, 3.5);
  }
}
